  edge_cases_json = '["Duplicate webhook events do not create duplicate entitlements.","Public /products/source-data exposes aggregate counts and redaction flags, not raw buyer rows.","A token created before a checkout state change is rejected while checkout state is no longer trusted paid or completed.","Owner-uploaded private assets are not yet customer-delivered.","Revocation, signed downloads, protected content, customer portal, refunds, and direct customer delivery of arbitrary uploads require later confirmed-write APIs.","Raw Stripe identifiers and buyer email remain server-private."]',
